from flask import Flask, render_template_string

app = Flask(__name__)

# Datos de ejemplo de autos JDM
cars = [
    {"name": "Nissan Skyline GT-R R34", "price": "$80,000 USD", "img": "data:image/jpeg;base64,"},
    {"name": "Toyota Supra MK4", "price": "$70,000 USD", "img": "data:image/jpeg;base64,"},
    {"name": "Mazda RX-7 FD", "price": "$60,000 USD", "img": "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR3_0ZG55K_UmPqJKUuIG2tcme7xsQPOK-SFA&s"},
    {"name": "Honda NSX", "price": "$90,000 USD", "img": "data:image/jpeg;base64,"}
]

html = """
<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <title>Tienda JDM</title>
    <style>
        body { font-family: Arial; background: #111; color: white; }
        .container { display: flex; flex-wrap: wrap; justify-content: center; }
        .card { background: #222; margin: 10px; padding: 15px; border-radius: 10px; width: 250px; text-align: center; }
        img { width: 100%; border-radius: 10px; }
        button { background: red; color: white; border: none; padding: 10px; cursor: pointer; }
        button:hover { background: darkred; }
    </style>
</head>
<body>
    <h1 style="text-align:center;">🚗 Tienda de Autos JDM</h1>
    <div class="container">
        {% for car in cars %}
        <div class="card">
            <img src="{{ car.img }}" alt="{{ car.name }}">
            <h2>{{ car.name }}</h2>
            <p>{{ car.price }}</p>
            <button onclick="alert('Compraste {{ car.name }}')">Comprar</button>
        </div>
        {% endfor %}
    </div>
</body>
</html>
"""

@app.route('/')
def home():
    return render_template_string(html, cars=cars)

if __name__ == '__main__':
    app.run(debug=True)
